{
  "studentLessonNotes": {
    "title": "Number System - Session 5: Rationalizing Denominators",
    "sessionOverview": "This session focuses on simplifying expressions with irrational denominators by rationalizing them, a key skill for Class IX Mathematics.",
    "introduction": "Welcome to Session 5! Today we tackle the tricky task of removing square roots from the bottom of fractions. You'll learn how to multiply by clever forms of '1' to make numbers easier to work with and compare.",
    "learningObjectives": [
      "After this lesson you will be able to rationalize denominators containing single radicals like √a",
      "You will understand why we rationalize fractions in mathematics",
      "You can simplify complex expressions involving sums of square roots"
    ],
    "quickRecall": [
      "Product rule for surds: √a × √b = √(ab)",
      "Difference of squares identity: (x - y)(x + y) = x² - y²",
      "Definition of a rational number"
    ],
    "easyToRemember": [
      "Multiply top and bottom by the same root to make it whole."
    ],
    "comparisonTables": [
      {
        "title": "Rational vs Irrational Denominators",
        "headers": [
          "Feature",
          "Irrational Denominator (Before)",
          "Rational Denominator (After)"
        ],
        "rows": [
          [
            "Example Form",
            "1 / √2",
            "√2 / 2"
          ],
          [
            "Decimal Approximation",
            "Approx. 0.707... (infinite)",
            "Exact value or easier to compute"
          ],
          [
            "Standard Form",
            "Not standard in higher math",
            "Preferred form for calculations"
          ]
        ]
      }
    ],
    "formulaCards": [
      {
        "title": "Rationalizing Single Root",
        "formula": {
          "text": "(√a) / (√b) = √(ab) / b",
          "latex": "\\frac{\\sqrt{a}}{\\sqrt{b}} \\times \\frac{\\sqrt{b}}{\\sqrt{b}}"
        },
        "meaning": "Multiply numerator and denominator by the same radical to create a perfect square in the denominator.",
        "whenToUse": "When you have a single square root like √2, √3, or √5 in the denominator."
      }
    ],
    "geometryDiagrams": [
      {
        "id": "diagram-1",
        "type": "sqrtNumberLineConstruction",
        "template": "sqrtNumberLineConstruction",
        "params": {
          "roots": [2, 3],
          "highlightRoot": 2
        },
        "title": "Constructing √2 on the Number Line",
        "caption": "Visualizing irrational numbers as lengths.",
        "points": [],
